      category: "Sports",
      sortBy: "volume",
      limit: 5,
      status: "open"
    }
  });

  const markets = browseResult?.markets || [];
  if (markets.length === 0) {
    return {
      error: "No active sports markets found on Kalshi.",
      browseResult
