  const crossRefResult = await callMcpSkill({
    toolId,
    toolName: "kalshi_crossref_polymarket",
    args: {
      title: title,
      kalshiTicker: ticker,
      limit: 3
    }
  });

  // 4. Return the combined data for comparison
  return {
    kalshiTopMarket: {
      title,
      ticker,
      yesPrice: yesPrice + "¢",
